package main

import (
	"bufio"
	"fmt"
	"os"
	"strconv"
	"strings"
)

type MyList struct {
	data []int
}

type Iterator struct {
	data  []int
	index int
}

type ReverseIterator struct {
	data []int
	index int
}

type CyclicIterator struct {
	data []int
	index int
}

func NewMyList(values []int) *MyList {
	return &MyList{data: values}
}

func (l *MyList) Iterator() *Iterator {
	return &Iterator{data: l.data, index: -1}
}

func (i *Iterator) HasNext() bool {
	return i.index < len(i.data)-1
}

func (i *Iterator) Next() int {
	if !i.HasNext() {
		panic(fmt.Errorf("No more elements"))
	}

	i.index++

	return i.data[i.index]
}

func (l *MyList) ReverseIterator() *ReverseIterator {
	return &ReverseIterator{
		data: l.data,
		index: len(l.data),
	}
}

func (l *MyList) CyclicIterator() *CyclicIterator {
	return &CyclicIterator{
		data:  l.data,
		index: -1,
	}
}

func (r *ReverseIterator) HasNext() bool {
	return r.index > 0
}

func (r *ReverseIterator) Next() int {

	if !r.HasNext() {
		panic(fmt.Errorf("No more elements"))
	}

	r.index--

	return r.data[r.index]
}

func (c *CyclicIterator) Next() int {

	if len(c.data) == 0 {
		panic(fmt.Errorf("Empty list"))
	}

	c.index++

	c.index = c.index % len(c.data)

	return c.data[c.index]
}

func main() {
	scanner := bufio.NewScanner(os.Stdin)
	mylist := NewMyList([]int{})
	for scanner.Scan() {
		line := scanner.Text()
		args := strings.Fields(line)
		fmt.Println("$" + line)

		switch args[0] {
		case "end":
			return
		case "read":
			for i := 1; i < len(args); i++ {
				slice := make([]int, len(args)-1)
				for i, value := range args[1:] {
					slice[i], _ = strconv.Atoi(value)
				}
				mylist = NewMyList(slice)
			}
		case "show":
			fmt.Print("[ ")
			for it := mylist.Iterator(); it.HasNext(); {
				fmt.Printf("%v ", it.Next())
			}
			fmt.Println("]")
		case "reverse":
			fmt.Print("[ ")
			for it := mylist.ReverseIterator(); it.HasNext(); {
				fmt.Printf("%v ", it.Next())
			}
			fmt.Println("]")
		case "cyclic":
			qtd, _ := strconv.Atoi(args[1])
			fmt.Print("[ ")
			it := mylist.CyclicIterator()
			for range qtd {
				fmt.Printf("%v ", it.Next())
			}
			fmt.Println("]")
		}
	}

}
